const CODE_SET = new Set<string>(["GEN","EXO","LEV","NUM","DEU","JOS","JDG","RUT","1SA","2SA","1KI","2KI","1CH","2CH","EZR","NEH","EST","JOB","PSA","PRO","ECC","SNG","ISA","JER","LAM","EZK","DAN","HOS","JOL","AMO","OBA","JON","MIC","NAM","HAB","ZEP","HAG","ZEC","MAL","MAT","MRK","LUK","JHN","ACT","ROM","1CO","2CO","GAL","EPH","PHP","COL","1TH","2TH","1TI","2TI","TIT","PHM","HEB","JAS","1PE","2PE","1JN","2JN","3JN","JUD","REV"]);

export function normalizeBookToCode(input: string): string {
  if (!input) return "";
  const up = input.trim().toUpperCase();
  if (CODE_SET.has(up)) return up;
  const key = input.trim().toLowerCase().replace(/\./g, "").replace(/\s+/g, " ");
  return BOOK_TO_CODE[key] ?? "";
}

