function toInt(value: string | number): number {
  if (typeof value === "number") return value;
  const m = String(value).match(/\d+/);
  return m ? parseInt(m[0], 10) : NaN;
}

function rangeContains(p: LifeEssentialsPrinciple, chapter: number, verse: number): boolean {
  if (Number.isNaN(chapter) || Number.isNaN(verse)) return false;
  const afterStart = chapter > p.startChapter || (chapter === p.startChapter && verse >= p.startVerse);
  const beforeEnd = chapter < p.endChapter || (chapter === p.endChapter && verse <= p.endVerse);
  return afterStart && beforeEnd;
}

// Index principles by code for fast lookup (1,500 records).
const BY_CODE: Record<string, LifeEssentialsPrinciple[]> = {};
for (const p of LIFE_ESSENTIALS_PRINCIPLES) {
  (BY_CODE[p.code] ||= []).push(p);
}

// Every Life Essentials principle whose passage range contains the given verse.
// `book` may be a full name, abbreviation, or USFM code (e.g. "Genesis", "Gen", "GEN").
export function getGeneGetzPrinciplesForVerse(
  book: string,
  chapter: string | number,
  verse: string | number,
): LifeEssentialsPrinciple[] {
  const code = normalizeBookToCode(book);
  if (!code) return [];
  const c = toInt(chapter);
  const v = toInt(verse);
  return (BY_CODE[code] ?? []).filter((p) => rangeContains(p, c, v));
}

export function formatPrincipleRange(p: LifeEssentialsPrinciple): string {
  if (p.startChapter === p.endChapter) {
    return p.startVerse === p.endVerse
      ? `${p.startChapter}:${p.startVerse}`
      : `${p.startChapter}:${p.startVerse}-${p.endVerse}`;
  }
  return `${p.startChapter}:${p.startVerse}-${p.endChapter}:${p.endVerse}`;
}

// Books that have principles (in canonical first-seen order).
export function seededPrincipleBooks(): string[] {
  const seen: string[] = [];
  for (const p of LIFE_ESSENTIALS_PRINCIPLES) if (!seen.includes(p.book)) seen.push(p.book);
  return seen;
}
